#include "msconnector/late_intervention.h"
void msconnector_late_intervention_policy_init(msconnector_late_intervention_policy *p) { if (p) { p->default_action = MSCONNECTOR_LATE_INTERVENTION_LOG_ONLY; p->strict_action = MSCONNECTOR_LATE_INTERVENTION_ABORT_CONNECTION; } }
const char *msconnector_late_intervention_action_name(msconnector_late_intervention_action a) { switch (a) { case MSCONNECTOR_LATE_INTERVENTION_LOG_ONLY: return "log_only"; case MSCONNECTOR_LATE_INTERVENTION_DENY_IF_POSSIBLE: return "deny_if_possible"; case MSCONNECTOR_LATE_INTERVENTION_ABORT_CONNECTION: return "abort_connection"; } return "unknown"; }
msconnector_late_intervention_action msconnector_late_intervention_resolve(const msconnector_late_intervention_policy *p, int h, int b, int strict) { msconnector_late_intervention_policy local; if (!p) { msconnector_late_intervention_policy_init(&local); p = &local; } if (strict) return p->strict_action; if (h || b) return p->default_action; return MSCONNECTOR_LATE_INTERVENTION_DENY_IF_POSSIBLE; }
